/* ─── SCREEN 2: CAMERA WITH REAL-TIME TIMESTAMP LOCK ─── */
function CameraScreen({ onCapture, onBack }) {
  const videoRef  = useRef(null);
  const canvasRef = useRef(null);
  const streamRef = useRef(null);
  
  // Real active stream state trackers
  const [gps, setGps] = useState(null);
  const [camReady, setCamReady] = useState(false);
  const [camErr, setCamErr] = useState(null);
  const [facing, setFacing] = useState('environment');
  const [flash, setFlash] = useState(false);

  const startCamera = useCallback(async (facingMode) => {
    try {
      if (streamRef.current) streamRef.current.getTracks().forEach(t=>t.stop());
      const stream = await navigator.mediaDevices.getUserMedia({
        video:{ facingMode, width:{ideal:1920}, height:{ideal:1080} }, audio:false
      });
      streamRef.current = stream;
      if (videoRef.current) { 
        videoRef.current.srcObject=stream; 
        await videoRef.current.play(); 
        setCamReady(true); 
        setCamErr(null); 
      }
    } catch(e) {
      setCamErr(e.name==='NotAllowedError'
        ?'Camera permission denied. Please allow camera access in your browser settings.'
        :'Camera not available on this device/browser.');
    }
  },[]);

  // Constant location watcher active on camera mount loop
  useEffect(()=>{
    startCamera(facing);
    if(navigator.geolocation){
      navigator.geolocation.getCurrentPosition(
        p=>setGps({lat:p.coords.latitude.toFixed(5),lng:p.coords.longitude.toFixed(5)}),
        ()=>setGps({lat:NAGPUR_BASE_LAT.toFixed(5),lng:NAGPUR_BASE_LNG.toFixed(5)}),
        {enableHighAccuracy: true, timeout:6000}
      );
    } else {
      setGps({lat:NAGPUR_BASE_LAT.toFixed(5),lng:NAGPUR_BASE_LNG.toFixed(5)});
    }
    return()=>{ if(streamRef.current) streamRef.current.getTracks().forEach(t=>t.stop()); };
  },[]);

  const flipCamera = async () => {
    const next = facing==='environment'?'user':'environment';
    setFacing(next);
    setCamReady(false);
    await startCamera(next);
  };

  // 🎯 REAL-TIME LOCATION LOCKED AT THE EXACT MOMENT SHUTTER IS PRESSED
  const shoot = () => {
    if(!camReady||!canvasRef.current||!videoRef.current) return;
    setFlash(true);
    setTimeout(()=>setFlash(false),180);
    
    const v=videoRef.current, c=canvasRef.current;
    c.width=v.videoWidth||1280; c.height=v.videoHeight||720;
    const ctx=c.getContext('2d');
    if(facing==='user'){ctx.translate(c.width,0);ctx.scale(-1,1);}
    ctx.drawImage(v,0,0,c.width,c.height);
    const dataURL=c.toDataURL('image/jpeg',0.88);

    if(streamRef.current) streamRef.current.getTracks().forEach(t=>t.stop());

    // Instant geolocation confirmation block on click matrix
    if (navigator.geolocation) {
      navigator.geolocation.getCurrentPosition(
        (p) => {
          const lockedGps = {lat: p.coords.latitude.toFixed(5), lng: p.coords.longitude.toFixed(5)};
          onCapture(dataURL, lockedGps);
        },
        () => {
          // If slow, fall back to background view metrics state cleanly
          const fallbackGps = gps || {lat: NAGPUR_BASE_LAT.toFixed(5), lng: NAGPUR_BASE_LNG.toFixed(5)};
          onCapture(dataURL, fallbackGps);
        },
        { enableHighAccuracy: true, timeout: 4000 }
      );
    } else {
      onCapture(dataURL, gps || {lat: NAGPUR_BASE_LAT.toFixed(5), lng: NAGPUR_BASE_LNG.toFixed(5)});
    }
  };

  return (
    <div style={{display:'flex',flexDirection:'column',flex:1,background:'#000',overflow:'hidden'}}>
      <canvas ref={canvasRef} style={{display:'none'}}/>
      <div style={{display:'flex',alignItems:'center',justifyContent:'space-between',padding:'12px 16px',position:'absolute',top:0,left:0,right:0,zIndex:10,background:'linear-gradient(to bottom,rgba(0,0,0,.65),transparent)'}}>
        <button onClick={onBack} style={{width:36,height:36,borderRadius:'50%',background:'rgba(0,0,0,.45)',border:'none',display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer'}}><X size={18} color="#fff"/></button>
        <div style={{display:'flex',alignItems:'center',gap:6,background:gps?'rgba(46,125,50,.85)':'rgba(21,101,192,.85)',padding:'5px 12px',borderRadius:99}}>
          <MapPin size={12} color="#fff"/>
          <span style={{fontSize:11,fontWeight:600,color:'#fff'}}>{gps?`${gps.lat}°N, ${gps.lng}°E`:'Syncing Live GPS…'}</span>
        </div>
        <button onClick={flipCamera} style={{width:36,height:36,borderRadius:'50%',background:'rgba(0,0,0,.45)',border:'none',display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer'}}><RotateCcw size={16} color="#fff"/></button>
      </div>

      <div style={{flex:1,position:'relative',overflow:'hidden',minHeight:280}}>
        {flash&&<div style={{position:'absolute',inset:0,background:'#fff',zIndex:20,opacity:.85}}/>}
        {camErr?(
          <div style={{position:'absolute',inset:0,display:'flex',flexDirection:'column',alignItems:'center',justifyContent:'center',padding:24,gap:12}}>
            <AlertTriangle size={40} color="#E65100"/>
            <div style={{color:'#fff',textAlign:'center',fontSize:13,lineHeight:1.6}}>{camErr}</div>
          </div>
        ):(
          <>
            <video ref={videoRef} playsInline muted style={{width:'100%',height:'100%',objectFit:'cover',transform:facing==='user'?'scaleX(-1)':'none'}}/>
            {[{t:18,l:18,bw:'3px 0 0 3px',br:'4px 0 0 0'},{t:18,r:18,bw:'3px 3px 0 0',br:'0 4px 0 0'},{b:18,l:18,bw:'0 0 3px 3px',br:'0 0 0 4px'},{b:18,r:18,bw:'0 3px 3px 0',br:'0 0 4px 0'}].map((g,i)=>(
              <div key={i} style={{position:'absolute',width:44,height:44,borderColor:'rgba(255,255,255,.75)',borderStyle:'solid',borderWidth:g.bw,borderRadius:g.br,top:g.t,left:g.l,right:g.r,bottom:g.b}}/>
            ))}
          </>
        )}
        {gps&&(
          <div style={{position:'absolute',bottom:10,left:10,width:110,height:80,borderRadius:8,overflow:'hidden',border:'2px solid rgba(255,255,255,.4)',zIndex:5}}>
            <LiveMap singlePin singleCoords={gps} height="80px" zoom={15}/>
          </div>
        )}
      </div>

      <div style={{background:'#111',padding:'18px 24px 26px',display:'flex',alignItems:'center',justifyContent:'space-between',flexShrink:0}}>
        <div style={{width:36}}/>
        <button onClick={shoot} disabled={!camReady||!!camErr}
          style={{width:72,height:72,borderRadius:'50%',background:C.white,border:'4px solid rgba(255,255,255,.3)',cursor:camReady?'pointer':'not-allowed',display:'flex',alignItems:'center',justifyContent:'center',padding:0,transition:'transform .1s'}}
          onMouseDown={e=>e.currentTarget.style.transform='scale(.9)'}
          onMouseUp={e=>e.currentTarget.style.transform='scale(1)'}>
          <div style={{width:56,height:56,borderRadius:'50%',background:camReady?C.white:'#555',border:`3px solid ${C.border}`}}/>
        </button>
        <button onClick={flipCamera} style={{width:36,height:36,borderRadius:'50%',background:'rgba(255,255,255,.1)',border:'none',display:'flex',alignItems:'center',justifyContent:'center',cursor:'pointer'}}><RotateCcw size={17} color="rgba(255,255,255,.7)"/></button>
      </div>
    </div>
  );
}

